def _detect_emotional_tone(text: str) -> str:
    # Simple emotional tone detection using basic sentiment markers
    emotional_markers = {
        'positive': ['happy', 'great', 'excellent', 'wonderful'],
        'negative': ['sad', 'angry', 'frustrated', 'upset'],
        'neutral': ['okay', 'fine', 'alright']
    }
    
    text_lower = text.lower()
    for tone, markers in emotional_markers.items():
        if any(marker in text_lower for marker in markers):
            return tone
    
    return 'neutral'

def _analyze_communication_pattern(conversation: list) -> str:
    # Basic communication pattern detection
    if len(conversation) < 2:
        return 'insufficient_data'
    
    pattern_indicators = {
        'repetitive': len(set(conversation)) < len(conversation) * 0.5,
        'escalating': any('!' in msg or msg.isupper() for msg in conversation[-3:]),
        'defensive': any(re.search(r'\b(but|however|actually)\b', msg, re.IGNORECASE) for msg in conversation)
    }
    
    detected_patterns = [p for p, v in pattern_indicators.items() if v]
    return ', '.join(detected_patterns) if detected_patterns else 'standard'

def _identify_potential_misunderstandings(current_msg: str, history: list) -> list:
    # Detect potential communication gaps or misunderstandings
    misunderstandings = []
    
    if len(history) > 0:
        last_msg = history[-1]
        
        # Check for semantic disconnection
